mapper.select:
SELECT staff_id, user_id, name, gender, birth_date, origin, id_card, avatar, resume,
       work_experience, hourly_rate, rating, verification_status, create_time, update_time
FROM staff

    AND gender = #{gender}
    AND origin LIKE CONCAT('%', #{origin}, '%')
    AND rating >= #{minRating}
    AND work_experience >= #{minWorkExperience}
    AND verification_status = #{verificationStatus}

ORDER BY rating DESC, work_experience DESC

mapper.update:
UPDATE staff
name = #{name}, gender = #{gender}, birth_date = #{birthDate}, origin = #{origin}, id_card = #{idCard}, avatar = #{avatar}, resume = #{resume}, work_experience = #{workExperience}, hourly_rate = #{hourlyRate}, rating = #{rating}, verification_status = #{verificationStatus},
WHERE staff_id = #{staffId}

UPDATE staff
SET verification_status = #{verificationStatus}
WHERE staff_id = #{staffId}
